"use client"

import * as React from "react"
import type { JsonSchemaLike } from "lemma-sdk"
import { useSchemaForm } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import { cn } from "@/lib/utils"

export interface LemmaSchemaFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSubmit"> {
  schema?: JsonSchemaLike | null
  uiSchema?: Record<string, unknown> | null
  initialValues?: Record<string, unknown>
  title?: string
  description?: string
  submitLabel?: string
  disabled?: boolean
  onSubmit?: (data: Record<string, unknown>) => Promise<void> | void
  onSubmitted?: (data: Record<string, unknown>) => void
  showReset?: boolean
  resetLabel?: string
  hiddenFields?: string[]
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
}

export const LemmaSchemaForm = React.forwardRef<HTMLDivElement, LemmaSchemaFormProps>(
  ({
    schema,
    uiSchema,
    initialValues,
    title = "Schema Form",
    description = "Generated from JSON Schema.",
    submitLabel = "Submit",
    disabled = false,
    onSubmit,
    onSubmitted,
    showReset = true,
    resetLabel = "Reset",
    hiddenFields = [],
    fieldLabels,
    fieldDescriptions,
    className,
    ...props
  }, ref) => {
  const form = useSchemaForm({
    schema,
    uiSchema,
    initialValues,
    onSubmit: async (data) => {
      await onSubmit?.(data)
      onSubmitted?.(data)
    },
  })

  const hasFields = form.fields.length > 0

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent>
        <form className="grid gap-4" onSubmit={handleSubmit}>
          {form.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {form.error.message}
            </div>
          ) : null}

          {!hasFields ? (
            <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
              This schema does not define any editable fields.
            </div>
          ) : null}

          {form.fields
            .filter((field) => !hiddenFields.includes(field.name))
            .map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const resolvedLabel = fieldLabels?.[field.name] ?? field.label
            const resolvedDescription = fieldDescriptions?.[field.name] ?? field.description
            const commonLabel = (
              <div className="grid gap-1.5">
                <Label htmlFor={field.name}>
                  {resolvedLabel}
                  {field.required ? " *" : ""}
                </Label>
                {resolvedDescription ? (
                  <p className="text-sm text-muted-foreground">{resolvedDescription}</p>
                ) : null}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="grid gap-2 rounded-lg border border-border bg-muted/30 p-4">
                  {commonLabel}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span>{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Textarea
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {commonLabel}
                <Input
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : field.kind === "email"
                            ? "email"
                            : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex items-center gap-2 pt-2">
            <Button disabled={disabled || form.isSubmitting} type="submit">
              {form.isSubmitting ? "Submitting…" : submitLabel}
            </Button>
            {showReset ? (
              <Button
                disabled={disabled || form.isSubmitting}
                onClick={() => form.reset()}
                type="button"
                variant="outline"
              >
                {resetLabel}
              </Button>
            ) : null}
          </div>
        </form>
      </CardContent>
    </Card>
  )
})
LemmaSchemaForm.displayName = "LemmaSchemaForm"

"use client"

import * as React from "react"
import type { Task } from "lemma-sdk"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { cn } from "@/lib/utils"

export interface LemmaAgentOutputCardProps extends React.HTMLAttributes<HTMLDivElement> {
  task?: Task | null
  output?: Record<string, unknown> | unknown[] | string | null
  finalOnly?: boolean
  title?: string
  description?: string
  emptyText?: string
}

function formatJson(value: unknown): string {
  if (value === null || typeof value === "undefined") return ""
  if (typeof value === "string") return value
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaAgentOutputCard = React.forwardRef<HTMLDivElement, LemmaAgentOutputCardProps>(
  ({
    task,
    output,
    finalOnly = false,
    title = "Agent Output",
    description = "Inspect the latest structured output from the selected task.",
    emptyText = "Run an agent to inspect output here.",
    className,
    ...props
  }, ref) => {
  const isFinal = task?.status === "COMPLETED" || task?.status === "FAILED" || task?.status === "CANCELLED" || task?.status === "STOPPED"
  const resolvedOutput = typeof output === "undefined" ? task?.output_data : output
  const visibleOutput = finalOnly && !isFinal ? null : resolvedOutput

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        {task ? (
          <div className="grid gap-2 rounded-md border border-border bg-muted/40 p-4 text-sm">
            <div className="font-medium">Status: {task.status}</div>
            <div className="truncate text-sm text-muted-foreground">Task ID: {task.id}</div>
          </div>
        ) : null}
        {visibleOutput ? (
          <pre className="max-h-[420px] overflow-auto rounded-md border border-border bg-muted/40 p-4 text-sm leading-6">
            {formatJson(visibleOutput)}
          </pre>
        ) : (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            {emptyText}
          </div>
        )}
      </CardContent>
    </Card>
  )
})
LemmaAgentOutputCard.displayName = "LemmaAgentOutputCard"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useAgentRun } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { cn } from "@/lib/utils"

export interface LemmaAgentMessagesProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  taskId?: string | null
  title?: string
  description?: string
}

function formatContent(value: unknown): string {
  if (typeof value === "string") return value
  if (value === null || typeof value === "undefined") return ""
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaAgentMessages = React.forwardRef<HTMLDivElement, LemmaAgentMessagesProps>(
  ({
    client,
    podId,
    taskId,
    title = "Agent Messages",
    description = "Task messages streamed or loaded from the selected agent run.",
    className,
    ...props
  }, ref) => {
  const run = useAgentRun({
    client,
    podId,
    taskId,
    autoConnect: false,
  })

  return (
    <Card ref={ref} className={cn("", className)} {...props}>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title}</CardTitle>
            <CardDescription>{description}</CardDescription>
          </div>
          <Button
            disabled={!taskId}
            onClick={() => {
              void run.loadMessages(taskId)
            }}
            variant="outline"
          >
            Refresh
          </Button>
        </div>
      </CardHeader>
      <CardContent className="flex flex-col gap-4">
        {run.error ? (
          <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            {run.error.message}
          </div>
        ) : null}
        {!taskId ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            Select or start an agent run to load messages.
          </div>
        ) : run.messages.length === 0 ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-4 py-8 text-sm text-muted-foreground">
            No messages loaded for this run.
          </div>
        ) : (
          run.messages.map((message) => (
            <div key={message.id} className="rounded-md border border-border bg-muted/30 p-4">
              <div className="mb-2 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                {message.role ?? "message"}
              </div>
              <pre className="whitespace-pre-wrap text-sm leading-6">
                {formatContent(message.content)}
              </pre>
            </div>
          ))
        )}
      </CardContent>
    </Card>
  )
})
LemmaAgentMessages.displayName = "LemmaAgentMessages"

"use client"

import * as React from "react"
import type { JsonSchemaLike, LemmaClient, Task } from "lemma-sdk"
import { useAgentInputSchema, useAgentRun } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { LemmaAgentMessages } from "@/components/lemma/lemma-agent-messages"
import { LemmaAgentOutputCard } from "@/components/lemma/lemma-agent-output-card"
import { LemmaSchemaForm } from "@/components/lemma/lemma-schema-form"
import { cn } from "@/lib/utils"

export interface LemmaAgentRunPanelProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  agentName: string
  inputSchema?: JsonSchemaLike | null
  title?: string
  description?: string
  onStarted?: (task: Task) => void
  onError?: (error: Error) => void
}

export const LemmaAgentRunPanel = React.forwardRef<HTMLDivElement, LemmaAgentRunPanelProps>(
  ({
    client,
    podId,
    agentName,
    inputSchema,
    title = "Agent Runner",
    description = "Start an agent with schema-aware input, then inspect status, output, and messages.",
    onStarted,
    onError,
    className,
    ...props
  }, ref) => {
  const [followUp, setFollowUp] = React.useState("")
  const [followUpError, setFollowUpError] = React.useState<string | null>(null)
  const schemaState = useAgentInputSchema({
    client,
    podId,
    agentName,
    enabled: !!agentName && !inputSchema,
  })
  const run = useAgentRun({
    client,
    podId,
    agentName: agentName || undefined,
    autoConnect: true,
    autoConnectOnStart: true,
  })
  const schema = inputSchema ?? schemaState.inputSchema

  React.useEffect(() => {
    if (schemaState.error) {
      onError?.(schemaState.error)
    }
  }, [schemaState.error, onError])

  React.useEffect(() => {
    if (run.error) {
      onError?.(run.error)
    }
  }, [run.error, onError])

  return (
    <div ref={ref} className={cn("grid gap-4", className)} {...props}>
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-4">
          {schemaState.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {schemaState.error.message}
            </div>
          ) : null}
          {run.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
              {run.error.message}
            </div>
          ) : null}
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="rounded-md border border-border bg-muted/30 p-4 text-sm">
              <div className="text-muted-foreground">Status</div>
              <div className="font-medium">{run.status ?? "idle"}</div>
            </div>
            <div className="rounded-md border border-border bg-muted/30 p-4 text-sm">
              <div className="text-muted-foreground">Task ID</div>
              <div className="truncate font-medium">{run.taskId ?? "none"}</div>
            </div>
          </div>
        </CardContent>
      </Card>

      <LemmaSchemaForm
        disabled={!agentName || run.isStreaming}
        description={schemaState.isLoading ? "Loading agent input schema..." : "Submit structured input to start this agent."}
        onSubmit={async (data) => {
          const task = await run.start(data)
          onStarted?.(task)
        }}
        schema={schema}
        submitLabel={run.isStreaming ? "Running..." : "Run agent"}
        title={agentName ? `Input: ${agentName}` : "Agent Input"}
      />

      {run.isWaitingForInput ? (
        <Card>
          <CardHeader>
            <CardTitle>Follow-up Input</CardTitle>
            <CardDescription>This run is waiting for a response before it can continue.</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-4">
            {followUpError ? (
              <div className="rounded-md border border-destructive/40 bg-destructive/10 px-4 py-3 text-sm text-destructive">
                {followUpError}
              </div>
            ) : null}
            <div className="grid gap-2">
              <Label htmlFor="lemma-agent-follow-up">Response</Label>
              <Textarea
                id="lemma-agent-follow-up"
                onChange={(event) => setFollowUp(event.target.value)}
                rows={4}
                value={followUp}
              />
            </div>
            <Button
              disabled={!followUp.trim()}
              onClick={async () => {
                setFollowUpError(null)
                try {
                  await run.submitInput(followUp)
                  setFollowUp("")
                } catch (error) {
                  const errorMsg = error instanceof Error ? error.message : "Failed to submit follow-up input."
                  setFollowUpError(errorMsg)
                  onError?.(error instanceof Error ? error : new Error(errorMsg))
                }
              }}
            >
              Submit response
            </Button>
          </CardContent>
        </Card>
      ) : null}

      <LemmaAgentOutputCard task={run.task} />
      <LemmaAgentMessages client={client} podId={podId} taskId={run.taskId} />
    </div>
  )
})
LemmaAgentRunPanel.displayName = "LemmaAgentRunPanel"
